function Register() {
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    email: '',
    first_name: '',
    last_name: '',
    role: 'patient',
    phone_number: '',
    date_of_birth: '',
    address: '',
    // Doctor fields
    specialization: 'General Physician',
    consultation_fee: 500,
    experience_years: 0,
    // Patient fields
    blood_group: '',
    medical_history: '',
  });

  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const handleInputChange = (e) => {
    const { id, value } = e.target;
    setFormData({
      ...formData,
      [id]: value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    // Basic Validation
    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters long.');
      setLoading(false);
      return;
    }

    try {
      const payload = { ...formData };

      // Clean up fields that don't match the selected role
      if (formData.role === 'patient') {
        delete payload.specialization;
        delete payload.consultation_fee;
        delete payload.experience_years;
      } else if (formData.role === 'doctor') {
        delete payload.blood_group;
        delete payload.medical_history;
      } else if (formData.role === 'admin') {
        delete payload.specialization;
        delete payload.consultation_fee;
        delete payload.experience_years;
        delete payload.blood_group;
        delete payload.medical_history;
      }

      await API.post('auth/register/', payload);

      setSuccess('Registration successful! Redirecting to login...');
      setTimeout(() => {
        navigate('/login');
      }, 1500);

    } catch (err) {
      console.error(err);
      if (err.response?.data) {
        const errors = err.response.data;
        const firstErrorKey = Object.keys(errors)[0];
        const errorVal = errors[firstErrorKey];
        setError(`${firstErrorKey.toUpperCase()}: ${Array.isArray(errorVal) ? errorVal[0] : errorVal}`);
      } else {
        setError('Something went wrong during registration. Please try again.');
      }
    } finally {
      setLoading(false);
