                <p style={{ background: 'rgba(0,0,0,0.3)', padding: '1rem', borderRadius: '8px', border: '1px solid var(--border-color)', whiteSpace: 'pre-wrap' }}>
                  {activePatient.patient_profile?.medical_history || 'No records provided.'}
