              </p>
              <div className="form-group">
                <label htmlFor="prescription">Doctor Notes / Prescription</label>
                <textarea 
                  id="prescription" 
                  rows={5}
                  value={prescriptionNotes}
                  onChange={(e) => setPrescriptionNotes(e.target.value)}
